import anthropic
import json
from datetime import datetime, timedelta

client = anthropic.Anthropic()

# User scheduling preferences
USER_PREFS = {
    "timezone": "America/New_York",
    "working_hours": {"start": "09:00", "end": "18:00"},
    "no_meeting_days": [],
    "focus_blocks": [
        {"day": "Monday", "start": "09:00", "end": "12:00"},
        {"day": "Wednesday", "start": "09:00", "end": "12:00"},
        {"day": "Friday", "start": "09:00", "end": "11:00"},
    ],
    "buffer_before_external_minutes": 15,
    "buffer_after_external_minutes": 10,
    "max_meetings_per_day": 4,
    "preferred_meeting_days": ["Tuesday", "Thursday"],
}

tools = [
    {
        "name": "get_availability",
        "description": (
            "Query free/busy slots for a list of attendees over a date range. "
            "Returns available windows as ISO 8601 time ranges."
        ),
        "input_schema": {
            "type": "object",
            "properties": {
                "attendees": {"type": "array", "items": {"type": "string"}},
                "start_date": {"type": "string"},
                "end_date": {"type": "string"},
                "duration_minutes": {"type": "integer"},
            },
            "required": ["attendees", "start_date", "end_date", "duration_minutes"],
        },
    },
    {
        "name": "create_calendar_event",
        "description": "Create a calendar event. Only called after user confirms the slot.",
        "input_schema": {
            "type": "object",
            "properties": {
                "title": {"type": "string"},
                "start": {"type": "string", "description": "ISO 8601 datetime"},
                "end": {"type": "string"},
                "attendees": {"type": "array", "items": {"type": "string"}},
                "description": {"type": "string"},
                "send_invites": {"type": "boolean"},
            },
            "required": ["title", "start", "end", "attendees"],
        },
    },
    {
        "name": "check_conflicts",
        "description": "Check if a proposed time slot conflicts with existing events for the user.",
        "input_schema": {
            "type": "object",
            "properties": {
                "start": {"type": "string"},
                "end": {"type": "string"},
            },
            "required": ["start", "end"],
        },
    },
    {
        "name": "propose_reschedule",
        "description": "Surface a rescheduling proposal to the user for confirmation before sending.",
        "input_schema": {
            "type": "object",
            "properties": {
                "event_title": {"type": "string"},
                "current_time": {"type": "string"},
                "proposed_time": {"type": "string"},
                "reason": {"type": "string"},
            },
            "required": ["event_title", "current_time", "proposed_time", "reason"],
        },
    },
]

def stub_tool(name: str, args: dict) -> str:
    if name == "get_availability":
        # Return mock free slots within working hours on preferred days
        return json.dumps({
            "available_slots": [
                {"start": "2024-07-16T14:00:00-04:00", "end": "2024-07-16T15:00:00-04:00"},
                {"start": "2024-07-16T15:30:00-04:00", "end": "2024-07-16T16:30:00-04:00"},
                {"start": "2024-07-18T13:00:00-04:00", "end": "2024-07-18T14:00:00-04:00"},
            ],
            "conflicts": [],
        })
    if name == "create_calendar_event":
        return json.dumps({"event_id": "cal_evt_789", "status": "created"})
    if name == "check_conflicts":
        return json.dumps({"conflicts": [], "within_focus_block": False, "within_working_hours": True})
    if name == "propose_reschedule":
        return json.dumps({"proposal_id": "prop_001", "status": "awaiting_user_confirmation"})
    return "Unknown tool"

def run_scheduling_agent(request: str) -> str:
    today = datetime.now().strftime("%Y-%m-%d")
    system = f"""You are a scheduling agent. User preferences:
{json.dumps(USER_PREFS, indent=2)}

Rules:
- Prefer slots on preferred_meeting_days (Tuesday, Thursday).
- Never schedule over focus blocks without explicit user instruction.
- Add buffer_before_external_minutes before and buffer_after_external_minutes after external meetings.
- Do not create events autonomously — surface the proposed slot for user confirmation first.
- Today: {today}"""

    messages = [{"role": "user", "content": request}]
    while True:
        response = client.messages.create(
            model="claude-opus-4-5", max_tokens=2048,
            system=system, tools=tools, messages=messages,
        )
        if response.stop_reason == "end_turn":
            for b in response.content:
                if b.type == "text":
                    return b.text
            return "Done"
        if response.stop_reason == "tool_use":
            messages.append({"role": "assistant", "content": response.content})
            results = []
            for b in response.content:
                if b.type == "tool_use":
                    results.append({
                        "type": "tool_result",
                        "tool_use_id": b.id,
                        "content": stub_tool(b.name, b.input),
                    })
            messages.append({"role": "user", "content": results})

result = run_scheduling_agent(
    "Schedule a 60-minute strategy review with emma@partner.com and raj@partner.com "
    "sometime this week. I want 15 minutes to prep beforehand."
)
print(result)
